import os
import sys
import time

class RouterHealthAgent:
    def __init__(self, config):
        self.config = config
        self.history = []

    def check_interface(self, iface_name):
        snmp_data = self._poll_snmp(iface_name)
        if snmp_data['errors'] > 100:
            self._raise_alert(iface_name, snmp_data)
        return snmp_data

    def _poll_snmp(self, iface, retries=3):
        for attempt in range(retries):
            try:
                return {'errors': 0, 'octets_in': 0, 'octets_out': 0}
            except Exception:
                time.sleep(2 ** attempt)
        return {}

    def _raise_alert(self, iface, data):
        self.history.append((iface, data))
